final class TransactionProcessor {
    private final AccountRepository repository;

    TransactionProcessor(@NonNull AccountRepository repository) {
        this.repository = repository;
    }

    synchronized TransactionResult process(@NonNull TransactionType type, @NonNull BigDecimal amount) {
        if (amount.compareTo(BigDecimal.ZERO) <= 0) {
            return new TransactionResult(false, "Amount must be greater than zero", repository.getBalance());
        }

        BigDecimal currentBalance = repository.getBalance();
        BigDecimal newBalance;

        if (type == TransactionType.DEPOSIT) {
            newBalance = currentBalance.add(amount);
        } else {
            if (currentBalance.compareTo(amount) < 0) {
                return new TransactionResult(false, "Insufficient funds", currentBalance);
            }
            newBalance = currentBalance.subtract(amount);
        }

        newBalance = Money.normalize(newBalance);
        repository.saveBalance(newBalance);
        return new TransactionResult(true, "Success", newBalance);
    }
}

final class AccountRepository {
    private static final String PREFS_NAME = "secure_banking_prefs";
    private static final String KEY_BALANCE = "encrypted_balance";
    private static final String KEY_IV = "encrypted_balance_iv";
    private static final String KEY_ALIAS = "banking_balance_key";
    private static final String LEGACY_PREFS = "legacy_banking_prefs";
    private static final String LEGACY_KEY_BALANCE = "legacy_balance";
    private final Context context;
    private final CryptoStore cryptoStore;

    AccountRepository(@NonNull Context context) {
        this.context = context.getApplicationContext();
        this.cryptoStore = new CryptoStore();
        migrateLegacyIfNeeded();
        if (!hasStoredBalance()) {
            saveBalance(BigDecimal.ZERO);
        }
    }

    synchronized BigDecimal getBalance() {
        try {
            String encrypted = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).getString(KEY_BALANCE, null);
            String iv = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).getString(KEY_IV, null);
            if (encrypted == null || iv == null) {
                return BigDecimal.ZERO.setScale(2, RoundingMode.HALF_EVEN);
            }
            String plain = cryptoStore.decrypt(KEY_ALIAS, encrypted, iv);
            return Money.parse(plain);
        } catch (Exception e) {
            return BigDecimal.ZERO.setScale(2, RoundingMode.HALF_EVEN);
        }
    }

    synchronized void saveBalance(@NonNull BigDecimal balance) {
        BigDecimal normalized = Money.normalize(balance);
        try {
            CryptoPayload payload = cryptoStore.encrypt(KEY_ALIAS, normalized.toPlainString());
            context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
                    .edit()
                    .putString(KEY_BALANCE, payload.cipherText)
                    .putString(KEY_IV, payload.iv)
                    .apply();
        } catch (Exception e) {
            throw new IllegalStateException("Unable to store balance securely", e);
        }
    }

    private boolean hasStoredBalance() {
        return context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).contains(KEY_BALANCE)
                && context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).contains(KEY_IV);
    }

    private void migrateLegacyIfNeeded() {
        if (hasStoredBalance()) {
            return;
        }
        String legacy = context.getSharedPreferences(LEGACY_PREFS, Context.MODE_PRIVATE).getString(LEGACY_KEY_BALANCE, null);
        if (legacy != null) {
            try {
                saveBalance(Money.parse(legacy));
                context.getSharedPreferences(LEGACY_PREFS, Context.MODE_PRIVATE).edit().remove(LEGACY_KEY_BALANCE).apply();
            } catch (Exception ignored) {
            }
        }
    }
}

